<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>2048</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #101014;
    color: #e6e1d5;
    font-family: "Helvetica Neue", Arial, sans-serif;
    padding: 24px;
  }
  .game { width: 460px; max-width: 100%; }
  .top { display: flex; align-items: center; gap: 12px; margin-bottom: 16px; }
  h1 { margin: 0; font-size: 52px; font-weight: 800; color: #edc22e; letter-spacing: 1px; }
  .score-box {
    margin-left: auto;
    background: #1d1d24;
    border-radius: 8px;
    padding: 8px 18px;
    text-align: center;
    min-width: 96px;
  }
  .score-box .label { font-size: 11px; letter-spacing: 2px; color: #8f8a9c; text-transform: uppercase; }
  #score { font-size: 26px; font-weight: 800; color: #ffffff; line-height: 1.1; }
  #reset {
    background: #8f7a66; color: #f9f6f2; border: 0; border-radius: 8px;
    font-size: 15px; font-weight: 700; padding: 12px 16px; cursor: pointer;
  }
  #reset:hover { background: #a08b74; }
  #reset:active { transform: translateY(1px); }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(4, 1fr);
    gap: 12px;
    background: #1a1a21;
    border-radius: 12px;
    padding: 12px;
    width: 100%;
    aspect-ratio: 1 / 1;
  }
  .cell {
    border-radius: 8px;
    background: #26262f;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 800;
    font-size: 44px;
    color: #f9f6f2;
    user-select: none;
    transition: background-color 120ms ease;
  }
  .v2    { background: #eee4da; color: #776e65; }
  .v4    { background: #ede0c8; color: #776e65; }
  .v8    { background: #f2b179; }
  .v16   { background: #f59563; }
  .v32   { background: #f67c5f; }
  .v64   { background: #f65e3b; }
  .v128  { background: #edcf72; font-size: 38px; }
  .v256  { background: #edcc61; font-size: 38px; }
  .v512  { background: #edc850; font-size: 38px; }
  .v1024 { background: #edc53f; font-size: 32px; }
  .v2048 { background: #edc22e; font-size: 32px; box-shadow: 0 0 18px rgba(237,194,46,.5); }
  .vsuper{ background: #3c3a32; font-size: 26px; }
  .hint { color: #7c7789; font-size: 14px; text-align: center; margin: 14px 0 0; }
  @media (max-width: 520px) {
    h1 { font-size: 40px; }
    .cell { font-size: 30px; }
    .v128, .v256, .v512 { font-size: 26px; }
    .v1024, .v2048 { font-size: 22px; }
  }
</style>
</head>
<body>
  <div class="game">
    <div class="top">
      <h1>2048</h1>
      <div class="score-box">
        <div class="label">Score</div>
        <div id="score">0</div>
      </div>
      <button id="reset" type="button">New Game</button>
    </div>
    <div id="board" aria-label="2048 board"></div>
    <p class="hint">Use the arrow keys to slide the tiles. Matching tiles merge into one.</p>
  </div>

<script>
(function () {
  "use strict";

  var SIZE = 4;
  var grid = [];
  var scoreVal = 0;

  var boardEl = document.getElementById("board");
  var scoreEl = document.getElementById("score");
  var resetBtn = document.getElementById("reset");

  // Build the 16 cell elements once; render() updates their contents.
  var cells = [];
  for (var i = 0; i < SIZE * SIZE; i++) {
    var c = document.createElement("div");
    c.className = "cell";
    boardEl.appendChild(c);
    cells.push(c);
  }

  function emptyGrid() {
    var g = [];
    for (var r = 0; r < SIZE; r++) {
      var row = [];
      for (var c = 0; c < SIZE; c++) row.push(0);
      g.push(row);
    }
    return g;
  }

  function emptyCells() {
    var list = [];
    for (var r = 0; r < SIZE; r++)
      for (var c = 0; c < SIZE; c++)
        if (grid[r][c] === 0) list.push([r, c]);
    return list;
  }

  function spawnTile() {
    var empties = emptyCells();
    if (empties.length === 0) return;
    var pick = empties[Math.floor(Math.random() * empties.length)];
    grid[pick[0]][pick[1]] = Math.random() < 0.9 ? 2 : 4;
  }

  function render() {
    for (var r = 0; r < SIZE; r++) {
      for (var c = 0; c < SIZE; c++) {
        var v = grid[r][c];
        var el = cells[r * SIZE + c];
        el.textContent = v === 0 ? "" : String(v);
        el.className = "cell" + (v ? " v" + (v <= 2048 ? v : "super") : "");
      }
    }
    scoreEl.textContent = String(scoreVal);
  }

  // Slide one line toward index 0, merging equal neighbours at most once each.
  function slideLine(line) {
    var nums = line.filter(function (v) { return v !== 0; });
    var out = [];
    var gained = 0;
    for (var i = 0; i < nums.length; i++) {
      if (i + 1 < nums.length && nums[i] === nums[i + 1]) {
        var merged = nums[i] * 2;
        out.push(merged);
        gained += merged;
        i++; // the consumed tile cannot merge again this move
      } else {
        out.push(nums[i]);
      }
    }
    while (out.length < SIZE) out.push(0);
    return { line: out, gained: gained };
  }

  // Read the line that slides toward the start of the given direction.
  function getLine(g, dir, i) {
    var line = [];
    for (var k = 0; k < SIZE; k++) {
      if (dir === "left")  line.push(g[i][k]);
      else if (dir === "right") line.push(g[i][SIZE - 1 - k]);
      else if (dir === "up")    line.push(g[k][i]);
      else                      line.push(g[SIZE - 1 - k][i]); // down
    }
    return line;
  }

  function setLine(g, dir, i, line) {
    for (var k = 0; k < SIZE; k++) {
      if (dir === "left")  g[i][k] = line[k];
      else if (dir === "right") g[i][SIZE - 1 - k] = line[k];
      else if (dir === "up")    g[k][i] = line[k];
      else                      g[SIZE - 1 - k][i] = line[k]; // down
    }
  }

  function move(dir) {
    if (dir !== "left" && dir !== "right" && dir !== "up" && dir !== "down") return false;
    var before = JSON.stringify(grid);
    var next = emptyGrid();
    var gained = 0;
    for (var i = 0; i < SIZE; i++) {
      var res = slideLine(getLine(grid, dir, i));
      gained += res.gained;
      setLine(next, dir, i, res.line);
    }
    if (JSON.stringify(next) === before) return false; // nothing changed: no spawn
    grid = next;
    scoreVal += gained;
    spawnTile();
    render();
    return true;
  }

  function reset() {
    grid = emptyGrid();
    scoreVal = 0;
    spawnTile();
    spawnTile();
    render();
  }

  function setBoard(arr) {
    grid = emptyGrid();
    for (var r = 0; r < SIZE; r++)
      for (var c = 0; c < SIZE; c++) {
        var v = arr && arr[r] ? Number(arr[r][c]) : 0;
        grid[r][c] = isFinite(v) && v > 0 ? Math.floor(v) : 0;
      }
    scoreVal = 0; // each freshly set board starts a clean scoring scenario
    render();
  }

  window.game = {
    size: SIZE,
    reset: reset,
    move: move,
    board: function () { return grid.map(function (row) { return row.slice(); }); },
    setBoard: setBoard,
    score: function () { return scoreVal; }
  };

  resetBtn.addEventListener("click", function () {
    reset();
    resetBtn.blur();
  });

  window.addEventListener("keydown", function (e) {
    var dir = null;
    if (e.key === "ArrowLeft") dir = "left";
    else if (e.key === "ArrowRight") dir = "right";
    else if (e.key === "ArrowUp") dir = "up";
    else if (e.key === "ArrowDown") dir = "down";
    if (dir) {
      e.preventDefault();
      move(dir);
    }
  });

  reset();
})();
</script>
</body>
</html>
